using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

public sealed partial class WebSearchTool
{
    private static readonly HttpClient HttpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description(
        "Searches the web for information on a query. " +
        "Returns a list of result titles, URLs, and snippet text. " +
        "Use different queries to explore various aspects of a topic.")]
    public static async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            var response = await HttpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new List<string>();

        var titleMatches = TitlePattern().Matches(html);
        var snippetMatches = SnippetPattern().Matches(html);

        var count = Math.Min(titleMatches.Count, 5);
        for (var i = 0; i < count; i++)
        {
            var title = WebUtility.HtmlDecode(
                StripHtmlTags(titleMatches[i].Groups[1].Value)).Trim();
            var snippet = i < snippetMatches.Count
                ? WebUtility.HtmlDecode(
                    StripHtmlTags(snippetMatches[i].Groups[1].Value)).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add($"[{i + 1}] {title}\n    {snippet}");
            }
        }

        return results.Count > 0
            ? $"Found {results.Count} results for the query:\n\n" +
              string.Join("\n\n", results)
            : "No results found. Try rephrasing the query.";
    }

    private static string StripHtmlTags(string input) =>
        HtmlTagPattern().Replace(input, string.Empty);

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]*>(.*?)</a>""",
        RegexOptions.Singleline)]
    private static partial Regex TitlePattern();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""",
        RegexOptions.Singleline)]
    private static partial Regex SnippetPattern();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagPattern();
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

public sealed class NoteTool
{
    private readonly List<(string Label, string Content)> _notes = [];

    [Description(
        "Saves a research note for later use in the summary. " +
        "Use this to record key facts, statistics, or insights found during research.")]
    public string SaveNote(
        [Description("A short label categorizing the note (e.g. 'definition', 'history', 'statistics')")] string label,
        [Description("The content of the note to save")] string content)
    {
        _notes.Add((label, content));
        return $"Note #{_notes.Count} saved under '{label}'.";
    }

    [Description(
        "Retrieves all saved research notes. " +
        "Call this when you are ready to write the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet. Use SaveNote to record findings first.";
        }

        var formatted = _notes.Select((n, i) =>
            $"Note #{i + 1} [{n.Label}]:\n{n.Content}");

        return $"All saved notes ({_notes.Count} total):\n\n" +
               string.Join("\n\n", formatted);
    }
}

