public sealed partial class WebSearchTool
{
    private static readonly HttpClient HttpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description(
        "Searches the web for information on a query. " +
        "Returns a list of result titles, URLs, and snippet text. " +
        "Use different queries to explore various aspects of a topic.")]
    public static async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            var response = await HttpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new List<string>();

        var titleMatches = TitlePattern().Matches(html);
        var snippetMatches = SnippetPattern().Matches(html);

        var count = Math.Min(titleMatches.Count, 5);
        for (var i = 0; i < count; i++)
        {
            var title = WebUtility.HtmlDecode(
                StripHtmlTags(titleMatches[i].Groups[1].Value)).Trim();
            var snippet = i < snippetMatches.Count
                ? WebUtility.HtmlDecode(
                    StripHtmlTags(snippetMatches[i].Groups[1].Value)).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add($"[{i + 1}] {title}\n    {snippet}");
            }
        }

        return results.Count > 0
            ? $"Found {results.Count} results for the query:\n\n" +
              string.Join("\n\n", results)
            : "No results found. Try rephrasing the query.";
