        "Saves a research note for later use in the summary. " +
        "Use this to record key facts, statistics, or insights found during research.")]
    public string SaveNote(
        [Description("A short label categorizing the note (e.g. 'definition', 'history', 'statistics')")] string label,
        [Description("The content of the note to save")] string content)
    {
