using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Register tools ---

var noteTool = new NoteTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
};

// --- Create the agent ---

const string agentInstructions = """
    You are a thorough research agent. Follow these steps:

    1. SEARCH: Use SearchWebAsync to search for information about the topic.
       Make at least 3 searches covering different aspects of the topic.
    2. TAKE NOTES: After each search, use SaveNote to record the most
       important facts, statistics, and insights you find.
    3. SUMMARIZE: Once you have gathered enough information, call GetNotes
       to retrieve all your notes, then write a well-organized summary.

    Your final summary should include:
    - A brief introduction to the topic
    - Key facts and details organized by theme
    - Notable statistics or data points
    - A conclusion with the current state or outlook

    Be factual and cite specific details from your research.
    """;

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    instructions: agentInstructions,
    tools: tools,
    loggerFactory: null,
    serviceProvider: null);

// --- Get topic from the user ---

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---

using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));

var session = await agent.CreateSessionAsync(conversationId: null, cts.Token);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
})
{
    // Keep tools in auto mode so the agent decides when to call them
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions,
    cts.Token);

// --- Display results ---

Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine("📝 RESEARCH SUMMARY");
Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("─────────────────────────────────────────");

if (response.Usage is { } usage)
{
    Console.WriteLine(
        $"\n📊 Tokens used — Input: {usage.InputTokenCount}, " +
        $"Output: {usage.OutputTokenCount}, " +
        $"Total: {usage.TotalTokenCount}");
}

